export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/health") {
      return json({ ok: true, service: "processing-worker" });
    }

    if (request.method === "POST" && url.pathname === "/jobs") {
      let body;
      try {
        body = await request.json();
      } catch {
        return json({ error: "Invalid JSON body" }, 400);
      }

      if (!body.auth?.authorized) {
        return json({ error: "Unauthorized upstream request" }, 403);
      }

      const result = {
        processed: true,
        input: body.input,
        metadata: body.metadata || {},
        userId: body.userId,
        traceId: body.traceId || request.headers.get("x-trace-id") || null,
      };

      if (env.NOTIFY_SERVICE) {
        ctx.waitUntil(
          env.NOTIFY_SERVICE.fetch(
            new Request("https://notify.internal/events", {
              method: "POST",
              headers: {
                "content-type": "application/json",
                "x-trace-id": result.traceId || "",
                "x-caller-service": "processing-worker",
              },
              body: JSON.stringify({
                type: "job.processed",
                payload: result,
              }),
            })
          )
        );
      }

      return json({
        service: "processing-worker",
        result,
      });
    }

    return json({ error: "Not found" }, 404);
  },
};

